var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"콜록! 콜록......!","JPN":"ゲホ、ゲホ……！","ENG":"*Cough!* *Cough!*","TWN":"咳咳！咳咳……！"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"리벳! 많이 다쳤어요?! 온몸이 피투성이예요!","JPN":"リベット！　怪我をしたのですか！？　全身血まみれですわ！","ENG":"Rivet! Are you okay? There's blood all over you!","TWN":"里維！妳傷得很嚴重嗎？！全身都是血！"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"RIVET_ESPR_NULL_NULL","text":{"KOREA":"괜찮아! 좀 스쳤을 뿐이야!","JPN":"大丈夫！　かすっただけだから！","ENG":"I'm fine, it's just a scratch.","TWN":"沒事！只是些擦傷而已！"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"머리에서 피가 철철 나는데 무슨 소리예요!","JPN":"頭から血がドクドク出てるのに、大丈夫なわけないでしょう！","ENG":"A scratch doesn't make you spew blood out of your head!","TWN":"妳頭上的血明明流得淅瀝嘩啦，在說什麼啊！"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L8_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"이리 와 봐요! 얼려 두면 당장 출혈은 막을 수 있을 거예요!","JPN":"こっちに来てください！　凍らせれば、とりあえず出血を止めることはできますから！","ENG":"Come over here. I'll freeze up the wound. That'll stop the bleeding for now.","TWN":"讓我看看！只要凍住馬上就可以止血了！"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"RIVET_ESPR_NULL_NULL","text":{"KOREA":"걱정해 줘서 고맙긴 한데...... 뒤 좀 돌아봐 줄래?","JPN":"心配してくれるのはありがたいんだけどさ……後ろ見てくれる？","ENG":"I appreciate your concern, but will you turn around?","TWN":"謝謝妳擔心我……但妳能回頭看一下嗎？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"네? 갑자기 뒤는 왜......?","JPN":"え？　後ろ……？","ENG":"Huh? For what?","TWN":"什麼？突然後面怎麼了？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"OCTOPUS3_ESPR_NULL_NULL","text":{"KOREA":"지식<color=#ff3636>의 성찬</color>이 준비되었<color=#ff3636>다. 연회가</color> 시작<b>되</b>었다.","JPN":"知識<color=#ff3636>の聖餐</color>の準備が整っ<color=#ff3636>た。宴会が</color> 始ま<b>っ</b>た。","ENG":"The fe<color=#ff3636>ast of know</color>ledge has be<color=#ff3636>en prepared. The banquet</color> has st<b>arte</b>d.","TWN":"知識<color=#ff3636>的饗宴</color>準備好<color=#ff3636>了。宴會</color>開<b>始</b>了。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OCTOPUS3_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"힉......?!","JPN":"ひッ……！？","ENG":"Hic...","TWN":"咿……？！"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"잔해들만 있는 줄 알았더니 웬 꼬마 아가씨들도 계셨군.","JPN":"残骸だけがいるのかと思ったら、お嬢さんたちもいたようだな。","ENG":"It's unexpected to see young ladies in a place filled with the Remains.","TWN":"我還以為只有殘骸呢，沒想到還有幾個小丫頭啊。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"BATTLE_NORMAL_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"나들이라도 나온 건가? 안타깝지만 장소를 잘못 고른 것 같은데.","JPN":"ピクニックにでも来たのか？　残念ながら、行き先を間違えたようだが。","ENG":"Are you out for an excursion? I must say, that was a terrible choice.","TWN":"是外出逛街嗎？很遺憾，你們似乎選錯地方了呢。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"BATTLE_NORMAL_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"도, 도와 주셔서 고마워요.","JPN":"た、助けてくださってありがとうございます。","ENG":"Th-thank you for your help.","TWN":"謝、謝你救了我們。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"BATTLE_NORMAL_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"그런데...... 누구시죠?","JPN":"ところで……どなたですか？","ENG":"May I ask who you are?","TWN":"不過……你是誰？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"BATTLE_NORMAL_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"모건, 새디어스 모건일세. 저 위에 떠 있는 함선을 타고 왔지.","JPN":"モーガン、タデウス・モーガンだ。あの上に浮いてる艦船に乗って来た。","ENG":"Morgan, Thaddeus Morgan. I came flying in that ship over there.","TWN":"我是摩根，薩迪烏斯·摩根，坐上面的艦船來的。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"BATTLE_NORMAL_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RYAN_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"뭐, 뭐라고요?","JPN":"な、何ですって？","ENG":"W-what?","TWN":"你、你說什麼？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"BATTLE_NORMAL_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"당신들 제정신인가요? 민간인 거주 구역에 함포를 쏘다니!","JPN":"あなたたち、正気ですか？　民間人居住区域に艦砲を撃つなんて！","ENG":"Are you out of your mind? How could you open fire in a civilian area?","TWN":"你們瘋了嗎？竟然炮擊平民的居住區域！"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"BATTLE_NORMAL_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"RYAN_PRYDWEN_NULL_NULL","text":{"KOREA":"민간인 거주 구역이라고? 여기가 말인가?","JPN":"民間人居住区域？　ここが？","ENG":"Civilian area? This place?","TWN":"平民居住區域？妳是說這裡嗎？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"BATTLE_NORMAL_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"RYAN_PRYDWEN_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L31_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"그럴 리가 없지. 여긴 마경이나 다름 없는 맥크레디 포인트의 한가운데야.","JPN":"そんなはずはない。ここは魔境のようなマクレディーポイントのど真ん中だぞ。","ENG":"You must be joking me. You're in the middle of MacCready Point, a virtual hell on earth.","TWN":"不可能吧。這裡可是等同於魔境的麥克蕾蒂要點正中央啊。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"BATTLE_NORMAL_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RYAN_PRYDWEN_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L32_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"젊은 아가씨가 뭔가 단단히 착각을 하고 있는 것 같군.","JPN":"お嬢さんは何か勘違いをしているようだな。","ENG":"I suggest you get your facts straight, young lady.","TWN":"看來這位年輕的小姐似乎有什麼嚴重的錯覺啊。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"BATTLE_NORMAL_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RYAN_PRYDWEN_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L34_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"그러고도 제 앞에 나타나다니 뻔뻔하시네요......!","JPN":"私を目の前にしてなんて図々しいことを……！","ENG":"And you have the audacity to stand in front of me!","TWN":"做了這種事還敢出現在我面前，真是厚顏無恥……！"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"BATTLE_NORMAL_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"맥크레디 가문의 후계자로서, 이번 일은 그냥 넘어갈 수 없어요!","JPN":"マクレディー家の後継者として、今回の件は看過できません！","ENG":"As the heir of the MacCready family, I won't let this pass!","TWN":"身為麥克蕾蒂家族的繼承人，我絕不會放過這件事！"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"BATTLE_NORMAL_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"반드시 관리국에 정식으로 항의하겠습니다!","JPN":"管理局へ正式に抗議させていただきます！","ENG":"I'll file an official complaint through the Administration!","TWN":"我一定會向管理局提出正式的抗議！"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"BATTLE_NORMAL_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"맥크레디 가문의 후계자라고? 자네가?","JPN":"マクレディー家の後継者だって？　君が？","ENG":"Heir of the MacCready family? You?","TWN":"妳說妳是麥克蕾蒂家族的繼承人？妳？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"BATTLE_NORMAL_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"RYAN_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L40_1","type":"dialog","speaker":"RYAN_PRYDWEN_NULL_NULL","text":{"KOREA":"생각했던 것과는 이미지가 많이 다르군.","JPN":"想像していた人物像とはかなり違いますね。","ENG":"You look nothing like I expected.","TWN":"和我想像的形象差很多啊。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"BATTLE_NORMAL_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"RYAN_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L41_1","type":"dialog","speaker":"RYAN_PRYDWEN_NULL_NULL","text":{"KOREA":"그렇다면 아가씨가 새로운 학회장인 겁니까?","JPN":"つまり、お嬢さんが新しい学会長なのですか？","ENG":"So are you the new President of the Society?","TWN":"那小姐妳就是新任的學會長了？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"BATTLE_NORMAL_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"RYAN_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L43_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"네? 아, 아니요. 전 학회장이 아닙니다.","JPN":"え？　い、いいえ。私は学会長ではありません。","ENG":"Huh? N-no, I'm not. I'm not the President.","TWN":"咦？不、不是的，我不是學會長。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"BATTLE_NORMAL_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"아니, 잠깐......","JPN":"あら、ところで……","ENG":"No, wait.","TWN":"不，等一下……"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"BATTLE_NORMAL_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"당신, 어떻게 학회에 대해 알고 있는 거죠?","JPN":"あなた、どうして学会のことを知っているんですか？","ENG":"How do you know about the Society?","TWN":"你怎麼會知道學會的事？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"BATTLE_NORMAL_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"그야 모를 리가 없지, 우리가 바로......","JPN":"知らないわけないだろ？　俺たちこそが……","ENG":"Well, of course we know. We're...","TWN":"我怎麼可能不知道嘛，畢竟我們就是來自……"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"BATTLE_NORMAL_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RYAN_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L1_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":"학회의 숙적, 프리드웬 기관의 사냥개들이니까요.","JPN":"学会の宿敵、プリドウェン機関の猟犬ですから。","ENG":"The hunting dogs of Prydwen Institution, the archenemy of the Society.","TWN":"學會的宿敵，普利多溫機關的獵犬。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"BATTLE_NORMAL_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L2_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"에델? 다치진 않았어?","JPN":"エデル？　怪我はしてない？","ENG":"Edel? Did you hurt yourself?","TWN":"艾瑟兒？妳沒受傷吧？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"BATTLE_NORMAL_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L3_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":"괜찮아요, 레지나 님. 걱정 마세요.","JPN":"大丈夫です、レジーナ様。ご心配なく。","ENG":"I'm fine, Miss Regina. Don't worry.","TWN":"我們沒事，蕾佳娜大人，請不要擔心。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"BATTLE_NORMAL_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L5_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":"이번 학회장을 맡게 된 에델 마이트너랍니다.","JPN":"今回、学会長を務めることになりましたエデル・マイトナーと申します。","ENG":"Edel Meitner, the newly appointed President of the Society.","TWN":"我們是目前擔任學會長的艾瑟兒·邁特納。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"BATTLE_NORMAL_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":"레지나 님에게서 물러서세요, 두 분.","JPN":"お二人とも、レジーナ様から離れてください。","ENG":"Step away from Miss Regina, you two.","TWN":"請從蕾佳娜大人身邊離開，兩位。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"BATTLE_NORMAL_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"......맥크레디 가문이 아닌 자가 학회장이라고? 그럴 수도 있나?","JPN":"……マクレディー家以外の者が学会長だと？　あり得るのか？","ENG":"Can a non-MacCready become the President? Is that even possible?","TWN":"……妳不屬於麥克蕾蒂家族，卻擔任了學會會長？還可以這樣嗎？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"BATTLE_NORMAL_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"RYAN_PRYDWEN_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L10_1","type":"dialog","speaker":"RYAN_PRYDWEN_NULL_NULL","text":{"KOREA":"상황이 생각했던 것보다 복잡한 모양이군.","JPN":"状況が思ったよりも複雑なようだな。","ENG":"The situation must be more complicated than we expected.","TWN":"看來情況比我想像得還要複雜啊。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"BATTLE_NORMAL_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"RYAN_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"RYAN_PRYDWEN_NULL_NULL","text":{"KOREA":"일단은 기관으로 연행해서 더 조사해 보는 게 좋겠어.","JPN":"とりあえず機関に連行して、もっと調査した方がいい。","ENG":"We'll have to haul them in for further investigation.","TWN":"總之，還是先帶到機關調查一下比較好。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"BATTLE_NORMAL_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"RYAN_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"듣자듣자 하니까...... 대체 누굴 연행한다는 거죠?!","JPN":"黙って聞いていれば……いったい、誰を連行するというのですか！？","ENG":"You and your despicable remarks... Whom are you saying to haul in?","TWN":"我越聽越火大了……你說要把誰帶走？！"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"BATTLE_NORMAL_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"전 이 영지를 수호할 책임이 있는 맥크레디 가문의 후계자, 레지나 맥크레디입니다!","JPN":"私はこの領地を守護する責任があるマクレディー家の後継者、レジーナ・マクレディーです！","ENG":"I am Regina MacCready! I'm the heir of the MacCready family, and I have the responsibility to defend this estate!","TWN":"我是負責守護這塊領地的麥克蕾蒂家族繼承人，蕾佳娜·麥克蕾蒂！"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"BATTLE_NORMAL_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"당신들 같은 불법 침입자들에게 굴복할 생각은 단 1그램도 없습니다!","JPN":"あなたたちのような不法侵入者に屈服する気は1ミリもありませんわ！","ENG":"There's no way that I'm succumbing to arrogant intruders like you!","TWN":"我絕不會向你們這種非法入侵者屈服的！"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"BATTLE_NORMAL_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"해 볼 테면 해 보시죠!","JPN":"やれるものならやってみなさい！","ENG":"Try me, if you will!","TWN":"能做到的話就試試看啊！"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"BATTLE_NORMAL_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":"레, 레지나님......","JPN":"レ、レジーナ様……","ENG":"M-Miss Regina...","TWN":"蕾、蕾佳娜大人……"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"BATTLE_NORMAL_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L19_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":"멋져...... 역시 학회를 이끌어가실 분......","JPN":"素敵……さすが、学会を率いるべきお方……","ENG":"How trustworthy... We expected no less from the rightful leader of the Society.","TWN":"好帥……不愧是即將帶領學會的人……"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"BATTLE_NORMAL_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L20_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":"저희도 전력으로 돕겠습니다.","JPN":"我々も全力でお手伝いいたします。","ENG":"We'll help with all our heart and soul!","TWN":"我們也會盡全力幫助您的。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"BATTLE_NORMAL_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":"레지나 님을 괴롭히는 자들은 모두...... 모두 잡아먹어 드릴게요!","JPN":"レジーナ様を苦しめる者たちは一人残らず……全員食べて差し上げます！","ENG":"We'll eat up anyone who tries to hurt you, Miss Regina!","TWN":"把欺負蕾佳娜大人的人，全部……全部都吃掉吧！"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"BATTLE_NORMAL_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_LAUGH"}}}}]`);export{e as default};